def solve(m, n, grid):
    visited = [[False]*n for _ in range(m)]
    shapes = set()
    def dfs(r, c, r0, c0, path):
        if r < 0 or r >= m or c < 0 or c >= n or visited[r][c] or grid[r][c] == 0:
            return
        visited[r][c] = True
        path.append((r - r0, c - c0))
        for dr, dc, d in [(-1,0,'U'),(1,0,'D'),(0,-1,'L'),(0,1,'R')]:
            dfs(r+dr, c+dc, r0, c0, path)
        path.append((0, 0))  # backtrack marker
    for r in range(m):
        for c in range(n):
            if grid[r][c] == 1 and not visited[r][c]:
                path = []
                dfs(r, c, r, c, path)
                shapes.add(tuple(path))
    return str(len(shapes))

